// SS11.1's caller-supplied narrow queue. When `pairs` is omitted this workflow builds its
// own (see 'Build narrow queue' below) -- both are supported so this workflow stays
// independently callable/testable without requiring f05-verify-claims to run first.
const item = $input.first().json;
const body = item.body || {};
const application_id = body.application_id || item.application_id;
if (!application_id) throw new Error('f05-contradiction-scan: application_id is required');
const pairs = Array.isArray(body.pairs) ? body.pairs : (Array.isArray(item.pairs) ? item.pairs : undefined);
const out = { application_id };
if (pairs) out.pairs = pairs;
return [{ json: out }];

// Called by 06/09/10, or by f05-verify-claims, as a sub-workflow with
