  });
}
const inp = $input.first().json;
// Entity gate step 2 (registrable-domain match) + human-readable disambiguators / LLM
// candidate_entity hints (design.md SS6, agents/entity-matcher.md's input contract).
const companyIds = Array.from(new Set((inp.scoped_rows || []).map(function (r) { return r.card_company_id; }).filter(Boolean)
  .concat(inp.company_id ? [inp.company_id] : [])));
const founderIds = inp.founder_ids || [];
const founders = founderIds.length
  ? await pgGet.call(this, 'founders?id=in.(' + founderIds.join(',') + ')&select=id,full_name') : [];
const companies = companyIds.length
  ? await pgGet.call(this, 'companies?id=in.(' + companyIds.join(',') + ')&select=id,name,domain,aliases') : [];
