const inp = $input.first().json;
const rows = inp.evidence_rows || [];
// design.md SS10.1 -- content_hash NOT NULL UNIQUE; PostgREST's on_conflict= +
// Prefer: resolution=ignore-duplicates is this workflow's equivalent of
