function entityForClaim(pair, applicationId) {
  if (pair.card_founder_id) return { entityType: 'founder', entityId: pair.card_founder_id };
  return { entityType: 'application', entityId: applicationId };
}

const inp = $input.first().json;
const candidatePairs = inp.candidate_pairs || [];
const contradictionByClaim = inp.contradiction_by_claim || {};
const gateFailuresByClaim = inp.gate_failures_by_claim || {};
const checkedAt = new Date().toISOString();
const ACTOR = 'f05-contradiction-scan';
const eventRows = [];
const contradictedClaimIds = new Set();

for (const pair of candidatePairs) {
  const ent = entityForClaim(pair, inp.application_id);
  eventRows.push({
    event_type: 'claim_verification_attempted', entity_type: ent.entityType, entity_id: ent.entityId,
    payload: {
      claim_id: pair.claim_id, class: null, check: 'contradiction_llm', question: pair.question,
      checked_at: checkedAt, run_id: inp.run_id, gate_failed: Boolean(gateFailuresByClaim[pair.claim_id]),
    },
    actor: ACTOR,
  });

  if (contradictionByClaim[pair.claim_id] && !contradictedClaimIds.has(pair.claim_id)) {
    contradictedClaimIds.add(pair.claim_id);
    const contradiction = contradictionByClaim[pair.claim_id];
    const base = {
      claim_id: pair.claim_id, class: null, check: 'contradiction_llm',
      verdict_before: null, verdict_after: null,
      source_url: contradiction.sourceUrl || null, checked_at: checkedAt, run_id: inp.run_id,
      nature: contradiction.nature, severity: contradiction.severity,
      found_reality: contradiction.foundReality, question: contradiction.question,
      agreed: contradiction.agreed, effective_tier: contradiction.effectiveTier,
    };
    // design.md SS9 -- application-fallback payload OMITS founder_claim and
    // entity_match.quote so an unpurgeable event never carries personal data.
    const payload = ent.entityType === 'application'
      ? Object.assign({}, base, {
          entity_match: contradiction.entityMatch
            ? { resolved_by: contradiction.entityMatch.resolved_by, disambiguator: contradiction.entityMatch.disambiguator }
            : null,
        })
      : Object.assign({ founder_claim: pair.founder_claim.text_verbatim }, base, { entity_match: contradiction.entityMatch });
    eventRows.push({ event_type: 'claim_contradicted', entity_type: ent.entityType, entity_id: ent.entityId, payload, actor: ACTOR });
  }
}

return [{ json: { ...inp, event_rows: eventRows } }];

